 20→#include "pj_ros_bridge/middleware/websocket_middleware.hpp"
 21→
 22→namespace pj_ros_bridge {
 23→
 24→WebSocketMiddleware::WebSocketMiddleware() : initialized_(false) {}
 25→
 26→WebSocketMiddleware::~WebSocketMiddleware() {
 27→  shutdown();
 28→}
 29→
 30→tl::expected<void, std::string> WebSocketMiddleware::initialize(uint16_t port) {
 31→  std::lock_guard<std::mutex> lock(state_mutex_);
 32→
 33→  if (initialized_) {
 34→    return tl::unexpected<std::string>("WebSocket middleware already initialized");
 35→  }
 36→
 37→  server_ = std::make_unique<ix::WebSocketServer>(port, "0.0.0.0");
 38→
 39→  server_->setOnClientMessageCallback([this](
 40→                                          std::shared_ptr<ix::ConnectionState> connection_state,
 41→                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 42→    // Guard against callbacks arriving after shutdown() has moved server_ out.
 43→    {
 44→      std::lock_guard<std::mutex> state_lock(state_mutex_);
 45→      if (!initialized_) {
 46→        return;
 47→      }
 48→    }
 49→
 50→    std::string client_id = connection_state->getId();
 51→
 52→    if (msg->type == ix::WebSocketMessageType::Open) {
 53→      // Store client connection
 54→      {
 55→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 56→        // Get a shared_ptr to this WebSocket from the server's client set
 57→        for (const auto& client : server_->getClients()) {
 58→          if (client.get() == &web_socket) {
 59→            clients_[client_id] = client;
 60→            break;
 61→          }
 62→        }
 63→      }
 64→
 65→      // Notify connect callback
 66→      ConnectionCallback cb;
 67→      {
 68→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 69→        cb = on_connect_;
 70→      }
 71→      if (cb) {
 72→        cb(client_id);
 73→      }
 74→
 75→    } else if (msg->type == ix::WebSocketMessageType::Close) {
 76→      // Notify disconnect callback
 77→      ConnectionCallback cb;
 78→      {
 79→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80→        cb = on_disconnect_;
 81→      }
 82→      if (cb) {
 83→        cb(client_id);
 84→      }
 85→
 86→      // Remove client connection
 87→      {
 88→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 89→        clients_.erase(client_id);
 90→      }
 91→
 92→    } else if (msg->type == ix::WebSocketMessageType::Message) {
 93→      if (!msg->binary) {
 94→        // Text message = API request, push to queue
 95→        IncomingRequest req;
 96→        req.client_id = client_id;
 97→        req.data.assign(msg->str.begin(), msg->str.end());
 98→
 99→        {
100→          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
101→          incoming_queue_.push(std::move(req));
102→        }
103→        queue_cv_.notify_one();
104→      }
105→      // Binary messages from clients are ignored (server-to-client only)
106→    }
107→  });
108→
109→  auto listen_result = server_->listen();
110→  if (!listen_result.first) {
111→    server_.reset();
112→    return tl::unexpected<std::string>(
113→        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
114→  }
115→
116→  server_->start();
117→  initialized_ = true;
118→
119→  return {};
120→}
121→
122→void WebSocketMiddleware::shutdown() {
123→  std::unique_ptr<ix::WebSocketServer> server_to_stop;
124→
125→  {
126→    std::lock_guard<std::mutex> lock(state_mutex_);
127→
128→    if (!initialized_) {
129→      return;
130→    }
131→
132→    initialized_ = false;
133→
134→    // Clear callbacks before stopping so that Close events fired during
135→    // stop() don't invoke into potentially destroyed objects (BridgeServer).
136→    on_connect_ = nullptr;
137→    on_disconnect_ = nullptr;
138→
139→    // Move server out — will be stopped outside the lock to avoid deadlock
140→    // with IO threads that acquire state_mutex_ in their Close callbacks.
141→    server_to_stop = std::move(server_);
142→  }
143→
144→  // Wake any thread blocked in receive_request()
145→  queue_cv_.notify_all();
146→
147→  // Stop the server WITHOUT holding state_mutex_.
148→  // IX IO threads fire Close callbacks that acquire state_mutex_;
149→  // releasing it first prevents the deadlock.
150→  if (server_to_stop) {
151→    server_to_stop->stop();
152→    server_to_stop.reset();
153→  }
154→
155→  // Clear client map
156→  {
157→    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
158→    clients_.clear();
159→  }
160→
161→  // Clear incoming queue
162→  {
163→    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
164→    std::queue<IncomingRequest> empty;
165→    std::swap(incoming_queue_, empty);
166→  }
167→}
