170→  {
171→    std::lock_guard<std::mutex> state_lock(state_mutex_);
172→    if (!initialized_) {
173→      return false;
174→    }
175→  }
176→
177→  std::unique_lock<std::mutex> lock(queue_mutex_);
178→
