208→bool SchemaExtractor::parse_message_type(
209→    const std::string& message_type, std::string& library_name, std::string& type_name) const {
210→  // Expected format: "package_name/msg/MessageType"
211→  size_t first_slash = message_type.find('/');
212→  if (first_slash == std::string::npos) {
213→    return false;
214→  }
215→
216→  size_t second_slash = message_type.find('/', first_slash + 1);
217→  if (second_slash == std::string::npos) {
218→    return false;
219→  }
220→
221→  library_name = message_type.substr(0, first_slash);
222→  type_name = message_type.substr(second_slash + 1);
223→
224→  return true;
225→}
