 27→
 28→bool GenericSubscriptionManager::subscribe(
 29→    const std::string& topic_name, const std::string& topic_type, MessageCallback callback) {
 30→  std::lock_guard<std::mutex> lock(mutex_);
 31→
 32→  auto it = subscriptions_.find(topic_name);
 33→
 34→  if (it != subscriptions_.end()) {
 35→    // Already subscribed - increment reference count
 36→    it->second.reference_count++;
 37→    return true;
 38→  }
 39→
 40→  // Create new subscription
 41→  try {
 42→    auto sub_callback = [topic_name, callback](std::shared_ptr<rclcpp::SerializedMessage> msg) {
 43→      uint64_t receive_time = get_current_time_ns();
 44→      callback(topic_name, msg, receive_time);
 45→    };
 46→
 47→    auto subscription = node_->create_generic_subscription(topic_name, topic_type, rclcpp::QoS(100), sub_callback);
 48→
 49→    SubscriptionInfo info;
 50→    info.subscription = subscription;
 51→    info.topic_type = topic_type;
 52→    info.callback = callback;
 53→    info.reference_count = 1;
 54→
 55→    subscriptions_[topic_name] = std::move(info);
 56→
 57→    return true;
 58→  } catch (const std::exception&) {
 59→    return false;
 60→  }
 61→}
