 63→bool GenericSubscriptionManager::unsubscribe(const std::string& topic_name) {
 64→  std::lock_guard<std::mutex> lock(mutex_);
 65→
 66→  auto it = subscriptions_.find(topic_name);
 67→  if (it == subscriptions_.end()) {
 68→    return false;  // Not subscribed
 69→  }
 70→
 71→  // Guard against underflow
 72→  if (it->second.reference_count == 0) {
 73→    return false;
 74→  }
 75→
 76→  // Decrement reference count
 77→  it->second.reference_count--;
 78→
 79→  // Remove subscription if no more references
 80→  if (it->second.reference_count == 0) {
 81→    subscriptions_.erase(it);
 82→  }
 83→
 84→  return true;
 85→}
