 19→
 20→#include "pj_ros_bridge/bridge_server.hpp"
 21→
 22→#include <map>
 23→#include <nlohmann/json.hpp>
 24→#include <unordered_set>
 25→
 26→#include "pj_ros_bridge/message_serializer.hpp"
 27→#include "pj_ros_bridge/message_stripper.hpp"
 28→#include "pj_ros_bridge/protocol_constants.hpp"
 29→
 30→using json = nlohmann::json;
 31→
 32→namespace pj_ros_bridge {
 33→
 34→BridgeServer::BridgeServer(
 35→    std::shared_ptr<rclcpp::Node> node, std::shared_ptr<MiddlewareInterface> middleware, int port,
 36→    double session_timeout, double publish_rate, bool strip_large_messages)
 37→    : node_(node),
 38→      middleware_(middleware),
 39→      port_(port),
 40→      session_timeout_(session_timeout),
 41→      publish_rate_(publish_rate),
 42→      initialized_(false),
 43→      total_messages_published_(0),
 44→      total_bytes_published_(0),
 45→      strip_large_messages_(strip_large_messages) {}
 46→
 47→BridgeServer::~BridgeServer() {
 48→  // Shut down the middleware before members are destroyed so that
 49→  // disconnect callbacks (which capture `this`) cannot fire into
 50→  // a partially destroyed BridgeServer.
 51→  if (middleware_) {
 52→    middleware_->shutdown();
 53→  }
 54→}
 55→
 56→bool BridgeServer::initialize() {
 57→  if (initialized_) {
 58→    RCLCPP_WARN(node_->get_logger(), "Bridge server already initialized");
 59→    return true;
 60→  }
 61→
 62→  RCLCPP_INFO(node_->get_logger(), "Initializing bridge server...");
 63→
 64→  // Create components before middleware init so callbacks can use them
 65→  topic_discovery_ = std::make_unique<TopicDiscovery>(node_);
 66→  schema_extractor_ = std::make_unique<SchemaExtractor>();
 67→  message_buffer_ = std::make_shared<MessageBuffer>();
 68→  subscription_manager_ = std::make_unique<GenericSubscriptionManager>(node_);
 69→  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 70→
 71→  RCLCPP_INFO(node_->get_logger(), "Core components created");
 72→
 73→  // Register disconnect callback before middleware init to avoid missing events
 74→  middleware_->set_on_disconnect([this](const std::string& client_id) {
 75→    RCLCPP_INFO(node_->get_logger(), "Client disconnected: '%s'", client_id.c_str());
 76→    cleanup_session(client_id);
 77→  });
 78→
 79→  // Initialize middleware (may start accepting connections immediately)
 80→  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 81→  if (!result) {
 82→    RCLCPP_ERROR(node_->get_logger(), "Failed to initialize middleware: %s", result.error().c_str());
 83→    return false;
 84→  }
 85→  RCLCPP_INFO(node_->get_logger(), "Middleware initialized (port: %d)", port_);
 86→
 87→  // Create session timeout timer (check every 1 second)
 88→  session_timeout_timer_ = node_->create_wall_timer(std::chrono::seconds(1), [this]() { check_session_timeouts(); });
 89→
 90→  RCLCPP_INFO(node_->get_logger(), "Session timeout monitoring started");
 91→
 92→  // Create message publisher timer (default: 50 Hz)
 93→  if (publish_rate_ <= 0.0) {
 94→    RCLCPP_ERROR(node_->get_logger(), "Invalid publish_rate: %.1f (must be > 0)", publish_rate_);
 95→    return false;
 96→  }
 97→  auto publish_period_ms = static_cast<int64_t>(1000.0 / publish_rate_);
 98→  publish_timer_ = node_->create_wall_timer(
 99→      std::chrono::milliseconds(publish_period_ms), [this]() { publish_aggregated_messages(); });
100→
101→  RCLCPP_INFO(node_->get_logger(), "Message aggregation publisher started at %.1f Hz", publish_rate_);
102→
103→  initialized_ = true;
104→  RCLCPP_INFO(node_->get_logger(), "Bridge server initialization complete");
105→
106→  return true;
107→}
108→
109→bool BridgeServer::process_requests() {
110→  if (!initialized_) {
111→    RCLCPP_ERROR(node_->get_logger(), "Bridge server not initialized");
112→    return false;
113→  }
114→
115→  // Receive request (non-blocking)
116→  std::vector<uint8_t> request_data;
117→  std::string client_id;
118→  bool received = middleware_->receive_request(request_data, client_id);
119→
120→  if (!received || request_data.empty()) {
121→    return false;  // No request pending
122→  }
123→
124→  // Convert request data to string
125→  std::string request(request_data.begin(), request_data.end());
126→  if (client_id.empty()) {
127→    RCLCPP_WARN(node_->get_logger(), "Received request with no client identity");
128→    return true;
129→  }
130→
131→  // Parse request JSON
132→  std::string response;
133→  json request_json;
134→  try {
135→    request_json = json::parse(request);
136→
137→    if (!request_json.contains("command")) {
138→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
139→    } else {
140→      std::string command = request_json["command"];
141→
142→      RCLCPP_DEBUG(node_->get_logger(), "Processing '%s' command from client '%s'", command.c_str(), client_id.c_str());
143→
144→      // Route to appropriate handler
145→      if (command == "get_topics") {
146→        response = handle_get_topics(client_id, request_json);
147→      } else if (command == "subscribe") {
148→        response = handle_subscribe(client_id, request_json);
149→      } else if (command == "unsubscribe") {
150→        response = handle_unsubscribe(client_id, request_json);
151→      } else if (command == "heartbeat") {
152→        response = handle_heartbeat(client_id, request_json);
153→      } else if (command == "pause") {
154→        response = handle_pause(client_id, request_json);
155→      } else if (command == "resume") {
156→        response = handle_resume(client_id, request_json);
157→      } else {
158→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
159→      }
160→    }
161→  } catch (const json::exception& e) {
162→    RCLCPP_ERROR(node_->get_logger(), "JSON parse error: %s", e.what());
163→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
164→  } catch (const std::exception& e) {
165→    RCLCPP_ERROR(node_->get_logger(), "Error processing request: %s", e.what());
166→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
167→  }
168→
169→  // Send response to the specific client
170→  std::vector<uint8_t> response_data(response.begin(), response.end());
171→  middleware_->send_reply(client_id, response_data);
172→  return true;
173→}
174→
175→std::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
176→  // Create session if it doesn't exist
177→  if (!session_manager_->session_exists(client_id)) {
178→    session_manager_->create_session(client_id);
179→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
180→  }
181→
182→  // Update heartbeat
183→  session_manager_->update_heartbeat(client_id);
184→
185→  // Discover topics
186→  auto topics = topic_discovery_->discover_topics();
187→
188→  // Build JSON response
189→  json response;
190→  response["status"] = "success";
191→  response["topics"] = json::array();
192→
193→  for (const auto& topic : topics) {
194→    json topic_entry;
195→    topic_entry["name"] = topic.name;
196→    topic_entry["type"] = topic.type;
197→    response["topics"].push_back(topic_entry);
198→  }
199→
200→  inject_response_fields(response, request);
201→
202→  RCLCPP_INFO(node_->get_logger(), "Returning %zu topics to client '%s'", topics.size(), client_id.c_str());
203→
204→  return response.dump();
205→}
206→
207→std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
208→  // Create session if it doesn't exist
209→  if (!session_manager_->session_exists(client_id)) {
210→    session_manager_->create_session(client_id);
211→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
212→  }
213→
214→  // Update heartbeat
215→  session_manager_->update_heartbeat(client_id);
216→
217→  if (!request.contains("topics")) {
218→    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
219→  }
220→
221→  if (!request["topics"].is_array()) {
222→    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
223→  }
224→
225→  // Get current subscriptions
226→  auto current_subs = session_manager_->get_subscriptions(client_id);
227→
228→  // Parse requested topics — supports mixed array of strings and objects:
229→  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
230→  std::unordered_map<std::string, double> requested_topics;
231→  for (const auto& topic : request["topics"]) {
232→    if (topic.is_string()) {
233→      requested_topics[topic.get<std::string>()] = 0.0;
234→    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
235→      double rate_hz = 0.0;
236→      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
237→        rate_hz = topic["max_rate_hz"].get<double>();
238→        if (rate_hz < 0.0) {
239→          rate_hz = 0.0;
240→        }
241→      }
242→      requested_topics[topic["name"].get<std::string>()] = rate_hz;
243→    }
244→  }
245→
246→  // Determine which topics to add (additive model - subscribe only adds, never removes)
247→  std::vector<std::string> topics_to_add;
248→
249→  // Find topics to add (in requested but not in current)
250→  for (const auto& [topic, rate] : requested_topics) {
251→    if (current_subs.find(topic) == current_subs.end()) {
252→      topics_to_add.push_back(topic);
253→    }
254→  }
255→
256→  // Get all available topics
257→  auto available_topics = topic_discovery_->discover_topics();
258→  std::unordered_map<std::string, std::string> topic_types;
259→  for (const auto& topic : available_topics) {
260→    topic_types[topic.name] = topic.type;
261→  }
262→
263→  // Subscribe to new topics - track successes and failures
264→  json schemas = json::object();
265→  json failures = json::array();
266→  std::unordered_set<std::string> successfully_subscribed;
267→
268→  for (const auto& topic_name : topics_to_add) {
269→    // Check if topic exists
270→    if (topic_types.find(topic_name) == topic_types.end()) {
271→      RCLCPP_WARN(
272→          node_->get_logger(), "Client '%s' requested non-existent topic '%s'", client_id.c_str(), topic_name.c_str());
273→      json failure;
274→      failure["topic"] = topic_name;
275→      failure["reason"] = "Topic does not exist";
276→      failures.push_back(failure);
277→      continue;
278→    }
279→
280→    std::string topic_type = topic_types[topic_name];
281→
282→    // Create callback to add messages to buffer (with optional stripping)
283→    auto callback = [this, topic_type](
284→                        const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg,
285→                        uint64_t receive_time_ns) {
286→      if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
287→        auto stripped = MessageStripper::strip(topic_type, *msg);
288→        auto stripped_ptr = std::make_shared<rclcpp::SerializedMessage>(std::move(stripped));
289→        message_buffer_->add_message(topic, receive_time_ns, stripped_ptr);
290→      } else {
291→        message_buffer_->add_message(topic, receive_time_ns, msg);
292→      }
293→    };
294→
295→    // Get schema BEFORE subscribing to avoid corrupting the reference count
296→    // if schema extraction fails after subscribe() increments it.
297→    std::string schema;
298→    try {
299→      schema = schema_extractor_->get_message_definition(topic_type);
300→    } catch (const std::exception& e) {
301→      RCLCPP_ERROR(node_->get_logger(), "Failed to get schema for topic '%s': %s", topic_name.c_str(), e.what());
302→      json failure;
303→      failure["topic"] = topic_name;
304→      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
305→      failures.push_back(failure);
306→      continue;
307→    }
308→
309→    // Subscribe via subscription manager
310→    bool success = subscription_manager_->subscribe(topic_name, topic_type, callback);
311→    if (!success) {
312→      RCLCPP_ERROR(node_->get_logger(), "Failed to subscribe to topic '%s'", topic_name.c_str());
313→      json failure;
314→      failure["topic"] = topic_name;
315→      failure["reason"] = "Subscription manager failed to create subscription";
316→      failures.push_back(failure);
317→      continue;
318→    }
319→
320→    nlohmann::json schema_obj;
321→    schema_obj["encoding"] = kSchemaEncodingRos2Msg;
322→    schema_obj["definition"] = schema;
323→    schemas[topic_name] = schema_obj;
324→    successfully_subscribed.insert(topic_name);
325→
326→    RCLCPP_INFO(
327→        node_->get_logger(), "Client '%s' subscribed to topic '%s' (type: %s)", client_id.c_str(), topic_name.c_str(),
328→        topic_type.c_str());
329→  }
330→
331→  // Update session subscriptions with successfully subscribed topics (additive model)
332→  std::unordered_map<std::string, double> final_subscriptions = current_subs;
333→  for (const auto& topic : successfully_subscribed) {
334→    final_subscriptions[topic] = requested_topics[topic];
335→  }
336→  // Update rates for topics that were already subscribed but may have a new rate
337→  for (const auto& [topic, rate] : requested_topics) {
338→    if (final_subscriptions.find(topic) != final_subscriptions.end()) {
339→      final_subscriptions[topic] = rate;
340→    }
341→  }
342→  session_manager_->update_subscriptions(client_id, final_subscriptions);
343→
344→  // Build response
345→  json response;
346→  if (failures.empty()) {
347→    response["status"] = "success";
348→  } else if (schemas.empty()) {
349→    // All subscriptions failed
350→    response["status"] = "error";
351→    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
352→    response["message"] = "Failed to subscribe to all requested topics";
353→  } else {
354→    // Partial success
355→    response["status"] = "partial_success";
356→    response["message"] = "Some subscriptions failed";
357→  }
358→
359→  response["schemas"] = schemas;
360→  if (!failures.empty()) {
361→    response["failures"] = failures;
362→  }
363→
364→  // Include rate limits in response for topics with non-zero rates
365→  json rate_limits = json::object();
366→  for (const auto& [topic, rate] : final_subscriptions) {
367→    if (rate > 0.0) {
368→      rate_limits[topic] = rate;
369→    }
370→  }
371→  if (!rate_limits.empty()) {
372→    response["rate_limits"] = rate_limits;
373→  }
374→
375→  inject_response_fields(response, request);
376→
377→  return response.dump();
378→}
379→
380→std::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
381→  // Create session if it doesn't exist
382→  if (!session_manager_->session_exists(client_id)) {
383→    session_manager_->create_session(client_id);
384→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
385→  }
386→
387→  // Update heartbeat
388→  session_manager_->update_heartbeat(client_id);
389→
390→  // Validate topics field
391→  if (!request.contains("topics") || !request["topics"].is_array()) {
392→    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
393→  }
394→
395→  // Get current subscriptions
396→  auto current_subs = session_manager_->get_subscriptions(client_id);
397→
398→  std::vector<std::string> removed;
399→
400→  for (const auto& topic_item : request["topics"]) {
401→    std::string topic_name;
402→    if (topic_item.is_string()) {
403→      topic_name = topic_item.get<std::string>();
404→    } else {
405→      continue;  // Skip invalid entries
406→    }
407→
408→    // Check if subscribed
409→    if (current_subs.find(topic_name) != current_subs.end()) {
410→      // Decrement subscription ref count
411→      subscription_manager_->unsubscribe(topic_name);
412→
413→      // Remove from client subscriptions
414→      current_subs.erase(topic_name);
415→
416→      removed.push_back(topic_name);
417→
418→      RCLCPP_INFO(
419→          node_->get_logger(), "Client '%s' unsubscribed from topic '%s'", client_id.c_str(), topic_name.c_str());
420→    }
421→  }
422→
423→  // Update session subscriptions
424→  session_manager_->update_subscriptions(client_id, current_subs);
425→
426→  // Build response
427→  json response;
428→  response["status"] = "success";
429→  response["removed"] = removed;
430→  inject_response_fields(response, request);
431→
432→  return response.dump();
433→}
434→
435→std::string BridgeServer::handle_heartbeat(const std::string& client_id, const nlohmann::json& request) {
436→  // Create session if it doesn't exist
437→  if (!session_manager_->session_exists(client_id)) {
438→    session_manager_->create_session(client_id);
439→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
440→  }
441→
442→  // Update heartbeat
443→  session_manager_->update_heartbeat(client_id);
444→
445→  RCLCPP_DEBUG(node_->get_logger(), "Heartbeat received from client '%s'", client_id.c_str());
446→
447→  // Build response
448→  json response;
449→  response["status"] = "ok";
450→  inject_response_fields(response, request);
451→
452→  return response.dump();
453→}
454→
455→std::string BridgeServer::handle_pause(const std::string& client_id, const nlohmann::json& request) {
456→  // Create session if it doesn't exist
457→  if (!session_manager_->session_exists(client_id)) {
458→    session_manager_->create_session(client_id);
459→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
460→  }
461→
462→  // Update heartbeat
463→  session_manager_->update_heartbeat(client_id);
464→
465→  // Check if already paused (idempotent)
466→  if (session_manager_->is_paused(client_id)) {
467→    RCLCPP_DEBUG(node_->get_logger(), "Client '%s' already paused", client_id.c_str());
468→    json response;
469→    response["status"] = "ok";
470→    response["paused"] = true;
471→    inject_response_fields(response, request);
472→    return response.dump();
473→  }
474→
475→  // Set paused state
476→  session_manager_->set_paused(client_id, true);
477→
478→  // Smart ROS2 management: decrement ref counts for all subscribed topics
479→  auto subs = session_manager_->get_subscriptions(client_id);
480→  for (const auto& [topic, rate] : subs) {
481→    subscription_manager_->unsubscribe(topic);
482→    RCLCPP_DEBUG(
483→        node_->get_logger(), "Decremented ref count for topic '%s' (client '%s' paused)", topic.c_str(),
484→        client_id.c_str());
485→  }
486→
487→  RCLCPP_INFO(node_->get_logger(), "Client '%s' paused (%zu topics refs decremented)", client_id.c_str(), subs.size());
488→
489→  json response;
490→  response["status"] = "ok";
491→  response["paused"] = true;
492→  inject_response_fields(response, request);
493→  return response.dump();
494→}
495→
496→std::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
497→  // Create session if it doesn't exist
498→  if (!session_manager_->session_exists(client_id)) {
499→    session_manager_->create_session(client_id);
500→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
501→  }
502→
503→  // Update heartbeat
504→  session_manager_->update_heartbeat(client_id);
505→
506→  // Check if not paused (idempotent)
507→  if (!session_manager_->is_paused(client_id)) {
508→    RCLCPP_DEBUG(node_->get_logger(), "Client '%s' not paused", client_id.c_str());
509→    json response;
510→    response["status"] = "ok";
511→    response["paused"] = false;
512→    inject_response_fields(response, request);
513→    return response.dump();
514→  }
515→
516→  // Set unpaused state
517→  session_manager_->set_paused(client_id, false);
518→
519→  // Smart ROS2 management: increment ref counts for all subscribed topics
520→  // Get all available topics for type lookup
521→  auto available_topics = topic_discovery_->discover_topics();
522→  std::unordered_map<std::string, std::string> topic_types;
523→  for (const auto& topic : available_topics) {
524→    topic_types[topic.name] = topic.type;
525→  }
526→
527→  auto subs = session_manager_->get_subscriptions(client_id);
528→  for (const auto& [topic, rate] : subs) {
529→    auto type_it = topic_types.find(topic);
530→    if (type_it != topic_types.end()) {
531→      std::string topic_type = type_it->second;
532→      auto callback = [this, topic_type](
533→                          const std::string& t, const std::shared_ptr<rclcpp::SerializedMessage>& msg,
534→                          uint64_t receive_time_ns) {
535→        if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
536→          auto stripped = MessageStripper::strip(topic_type, *msg);
537→          auto stripped_ptr = std::make_shared<rclcpp::SerializedMessage>(std::move(stripped));
538→          message_buffer_->add_message(t, receive_time_ns, stripped_ptr);
539→        } else {
540→          message_buffer_->add_message(t, receive_time_ns, msg);
541→        }
542→      };
543→      subscription_manager_->subscribe(topic, topic_type, callback);
544→      RCLCPP_DEBUG(
545→          node_->get_logger(), "Incremented ref count for topic '%s' (client '%s' resumed)", topic.c_str(),
546→          client_id.c_str());
547→    } else {
548→      RCLCPP_WARN(
549→          node_->get_logger(), "Topic '%s' no longer exists, cannot re-subscribe for client '%s'", topic.c_str(),
550→          client_id.c_str());
551→    }
552→  }
553→
554→  RCLCPP_INFO(node_->get_logger(), "Client '%s' resumed (%zu topics refs incremented)", client_id.c_str(), subs.size());
555→
556→  json response;
557→  response["status"] = "ok";
558→  response["paused"] = false;
559→  inject_response_fields(response, request);
560→  return response.dump();
561→}
562→
563→void BridgeServer::inject_response_fields(nlohmann::json& response, const nlohmann::json& request) const {
564→  response["protocol_version"] = kProtocolVersion;
565→  if (request.contains("id") && request["id"].is_string()) {
566→    response["id"] = request["id"];
567→  }
568→}
569→
570→std::string BridgeServer::create_error_response(
571→    const std::string& error_code, const std::string& message, const nlohmann::json& request) const {
572→  json response;
573→  response["status"] = "error";
574→  response["error_code"] = error_code;
575→  response["message"] = message;
576→  inject_response_fields(response, request);
577→
578→  return response.dump();
579→}
