581→void BridgeServer::check_session_timeouts() {
582→  auto timed_out_sessions = session_manager_->get_timed_out_sessions();
583→
584→  for (const auto& client_id : timed_out_sessions) {
585→    RCLCPP_WARN(node_->get_logger(), "Session timeout for client '%s'", client_id.c_str());
586→
587→    cleanup_session(client_id);
588→  }
589→}
590→
591→void BridgeServer::cleanup_session(const std::string& client_id) {
592→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
593→
594→  // Check if session still exists (idempotency guard)
595→  if (!session_manager_->session_exists(client_id)) {
596→    return;
597→  }
598→
599→  // Get client's subscriptions and paused state
600→  auto subscriptions = session_manager_->get_subscriptions(client_id);
601→  bool was_paused = session_manager_->is_paused(client_id);
602→
603→  // Unsubscribe from all topics (only if not paused - paused clients already decremented ref counts)
604→  if (!was_paused) {
605→    for (const auto& [topic, rate] : subscriptions) {
606→      subscription_manager_->unsubscribe(topic);
607→      RCLCPP_DEBUG(node_->get_logger(), "Unsubscribed client '%s' from topic '%s'", client_id.c_str(), topic.c_str());
608→    }
609→  }
610→
611→  // Remove session
612→  session_manager_->remove_session(client_id);
613→
614→  // Clean up rate-limit tracking for this client
615→  {
616→    std::lock_guard<std::mutex> lock(last_sent_mutex_);
617→    last_sent_times_.erase(client_id);
618→  }
619→
620→  RCLCPP_INFO(
621→      node_->get_logger(), "Cleaned up session for client '%s' (%zu topics unsubscribed)", client_id.c_str(),
622→      subscriptions.size());
623→}
624→
625→size_t BridgeServer::get_active_session_count() const {
626→  return session_manager_->session_count();
627→}
