  73→    return true;
  74→  }
  75→
  76→  bool send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) override {
  77→    std::lock_guard<std::mutex> lock(binary_mutex_);
  78→    binary_sends_.emplace_back(client_identity, data);
  79→    return true;
  80→  }
  81→
  82→  bool is_ready() const override {
  83→    return ready_;
  84→  }
  85→
  86→  void set_on_connect(ConnectionCallback callback) override {
  87→    std::lock_guard<std::mutex> lock(cb_mutex_);
  88→    on_connect_ = std::move(callback);
  89→  }
  90→
  91→  void set_on_disconnect(ConnectionCallback callback) override {
  92→    std::lock_guard<std::mutex> lock(cb_mutex_);
  93→    on_disconnect_ = std::move(callback);
  94→  }
  95→
  96→  // --- Test helpers ---
  97→
  98→  /// Push a text request as if it came from a connected client.
  99→  void push_request(const std::string& client_id, const std::string& text) {
 100→    std::lock_guard<std::mutex> lock(queue_mutex_);
 101→    std::vector<uint8_t> data(text.begin(), text.end());
 102→    request_queue_.emplace_back(client_id, std::move(data));
 103→  }
 104→
 105→  /// Invoke the disconnect callback registered by BridgeServer.
 106→  void simulate_disconnect(const std::string& client_id) {
 107→    ConnectionCallback cb;
 108→    {
 109→      std::lock_guard<std::mutex> lock(cb_mutex_);
 110→      cb = on_disconnect_;
 111→    }
 112→    if (cb) {
 113→      cb(client_id);
 114→    }
 115→  }
 116→
 117→  /// Invoke the connect callback registered by BridgeServer.
 118→  void simulate_connect(const std::string& client_id) {
 119→    ConnectionCallback cb;
 120→    {
 121→      std::lock_guard<std::mutex> lock(cb_mutex_);
 122→      cb = on_connect_;
 123→    }
 124→    if (cb) {
 125→      cb(client_id);
 126→    }
 127→  }
 128→
 129→  /// Get the most recent reply sent to a given client (empty json on miss).
 130→  json pop_reply(const std::string& client_id) {
 131→    std::lock_guard<std::mutex> lock(reply_mutex_);
 132→    for (auto it = replies_.rbegin(); it != replies_.rend(); ++it) {
 133→      if (it->first == client_id) {
 134→        std::string text(it->second.begin(), it->second.end());
 135→        json j = json::parse(text, nullptr, false);
 136→        replies_.erase(std::next(it).base());
 137→        return j;
 138→      }
 139→    }
 140→    return json{};
 141→  }
 142→
 143→  /// Return all recorded binary sends (client_id, raw bytes).
 144→  std::vector<std::pair<std::string, std::vector<uint8_t>>> get_binary_sends() {
 145→    std::lock_guard<std::mutex> lock(binary_mutex_);
 146→    return binary_sends_;
 147→  }
 148→
 149→  void clear_binary_sends() {
 150→    std::lock_guard<std::mutex> lock(binary_mutex_);
 151→    binary_sends_.clear();
 152→  }
 153→
 154→ private:
 155→  bool ready_{false};
 156→
 157→  std::mutex queue_mutex_;
 158→  std::deque<std::pair<std::string, std::vector<uint8_t>>> request_queue_;
 159→
 160→  std::mutex reply_mutex_;
 161→  std::vector<std::pair<std::string, std::vector<uint8_t>>> replies_;
 162→
 163→  std::mutex binary_mutex_;
 164→  std::vector<std::pair<std::string, std::vector<uint8_t>>> binary_sends_;
 165→
 166→  std::mutex cb_mutex_;
 167→  ConnectionCallback on_connect_;
 168→  ConnectionCallback on_disconnect_;
 169→};
