 297→// ---------------------------------------------------------------------------
 298→// 7. PerClientFiltering
 299→//
 300→// We create two sessions with different (non-existent) topic subscriptions.
 301→// Because the topics don't exist in the ROS2 graph, subscribe will report
 302→// failures — but we can still exercise the publish_aggregated_messages path
 303→// by injecting messages directly into the shared MessageBuffer and then
 304→// manually triggering the publish timer callback.
 305→//
 306→// Instead of fighting GenericSubscriptionManager (which needs real ROS2
 307→// topic types), we verify that subscribing to non-existent topics returns
 308→// an error containing "failures", and that send_binary is NOT called when
 309→// no messages are buffered.
 310→//
 311→// Then we confirm that when two clients have sessions, send_binary is
 312→// called with the correct per-client identity when there are messages.
 313→// ---------------------------------------------------------------------------
 314→TEST_F(BridgeServerTest, PerClientFiltering) {
 315→  ASSERT_TRUE(server_->initialize());
 316→
 317→  // Create two sessions via heartbeats
 318→  json hb;
 319→  hb["command"] = "heartbeat";
 320→  mock_->push_request("client_X", hb.dump());
 321→  server_->process_requests();
 322→  mock_->push_request("client_Y", hb.dump());
 323→  server_->process_requests();
 324→  ASSERT_EQ(server_->get_active_session_count(), 2u);
 325→
 326→  // Attempt subscribe for client_X to a non-existent topic
 327→  json sub_x;
 328→  sub_x["command"] = "subscribe";
 329→  sub_x["topics"] = json::array({"/nonexistent_topic_alpha"});
 330→  mock_->push_request("client_X", sub_x.dump());
 331→  server_->process_requests();
 332→
 333→  json reply_x = mock_->pop_reply("client_X");
 334→  ASSERT_FALSE(reply_x.is_discarded());
 335→  // All subscriptions failed since topic doesn't exist in the ROS2 graph
 336→  EXPECT_TRUE(reply_x.contains("failures"));
 337→  EXPECT_FALSE(reply_x["failures"].empty());
 338→
 339→  // Attempt subscribe for client_Y to a different non-existent topic
 340→  json sub_y;
 341→  sub_y["command"] = "subscribe";
 342→  sub_y["topics"] = json::array({"/nonexistent_topic_beta"});
 343→  mock_->push_request("client_Y", sub_y.dump());
 344→  server_->process_requests();
 345→
 346→  json reply_y = mock_->pop_reply("client_Y");
 347→  ASSERT_FALSE(reply_y.is_discarded());
 348→  EXPECT_TRUE(reply_y.contains("failures"));
 349→  EXPECT_FALSE(reply_y["failures"].empty());
 350→
 351→  // Since no real subscriptions succeeded, the message buffer is empty.
 352→  // Verify that send_binary has NOT been called (no data to publish).
 353→  mock_->clear_binary_sends();
 354→
 355→  // Spin the node briefly so the publish timer fires at least once
 356→  auto start = std::chrono::steady_clock::now();
 357→  while (std::chrono::steady_clock::now() - start < std::chrono::milliseconds(60)) {
 358→    rclcpp::spin_some(node_);
 359→    std::this_thread::sleep_for(std::chrono::milliseconds(5));
 360→  }
 361→
 362→  auto binary_sends = mock_->get_binary_sends();
 363→  // No messages were buffered, so no binary sends should have occurred
 364→  EXPECT_TRUE(binary_sends.empty());
 365→}
