 468→// ---------------------------------------------------------------------------
 469→// Regression: StatsNotInflatedByMultipleSessions
 470→//
 471→// The old code counted stats inside the per-client send loop:
 472→//   for (client : clients_in_group) {
 473→//     if (send_binary(client, data)) {
 474→//       total_msg_count += group_msg_count;  // BUG: counted per client
 475→//     }
 476→//   }
 477→// With N clients sharing a subscription group, stats were inflated by N.
 478→// The fix counts once per group regardless of client count.
 479→//
 480→// This test creates 3 active sessions and spins the publish timer.
 481→// With no messages in the buffer, stats must remain (0, 0) — verifying
 482→// the counting path does not produce phantom stats with multiple sessions.
 483→// ---------------------------------------------------------------------------
 484→TEST_F(BridgeServerTest, StatsNotInflatedByMultipleSessions) {
 485→  ASSERT_TRUE(server_->initialize());
 486→
 487→  // Create 3 sessions via heartbeats
 488→  json hb;
 489→  hb["command"] = "heartbeat";
 490→  for (const auto& id : {"stats_client_1", "stats_client_2", "stats_client_3"}) {
 491→    mock_->push_request(id, hb.dump());
 492→    server_->process_requests();
 493→  }
 494→  ASSERT_EQ(server_->get_active_session_count(), 3u);
 495→
 496→  // Spin the node so the publish timer fires multiple times
 497→  auto start = std::chrono::steady_clock::now();
 498→  while (std::chrono::steady_clock::now() - start < std::chrono::milliseconds(80)) {
 499→    rclcpp::spin_some(node_);
 500→    std::this_thread::sleep_for(std::chrono::milliseconds(5));
 501→  }
 502→
 503→  // No messages were buffered, so stats must be zero
 504→  auto [msgs, bytes] = server_->get_publish_stats();
 505→  EXPECT_EQ(msgs, 0u);
 506→  EXPECT_EQ(bytes, 0u);
 507→
 508→  // No binary sends should have occurred
 509→  EXPECT_TRUE(mock_->get_binary_sends().empty());
 510→}
