1142→// PausedClientDoesNotReceiveBinaryFrames
1143→//
1144→// Tests that paused clients are skipped when publishing binary frames.
1145→// Since we can't easily inject messages into the buffer, we verify the
1146→// paused state is respected by checking that a paused client with a
1147→// subscription group is skipped.
1148→// ---------------------------------------------------------------------------
1149→TEST_F(BridgeServerTest, PausedClientDoesNotReceiveBinaryFrames) {
1150→  ASSERT_TRUE(server_->initialize());
1151→
1152→  // Create two sessions via heartbeats
1153→  json hb;
1154→  hb["command"] = "heartbeat";
1155→  mock_->push_request("client_paused_1", hb.dump());
1156→  server_->process_requests();
1157→  mock_->push_request("client_active_1", hb.dump());
1158→  server_->process_requests();
1159→  ASSERT_EQ(server_->get_active_session_count(), 2u);
1160→
1161→  // Subscribe both clients to the same non-existent topic
1162→  // (subscription will fail but session subscription intent is tracked)
1163→  json sub_req;
1164→  sub_req["command"] = "subscribe";
1165→  sub_req["topics"] = json::array({"/test_topic"});
1166→  mock_->push_request("client_paused_1", sub_req.dump());
1167→  server_->process_requests();
1168→  mock_->pop_reply("client_paused_1");  // discard
1169→
1170→  mock_->push_request("client_active_1", sub_req.dump());
1171→  server_->process_requests();
1172→  mock_->pop_reply("client_active_1");  // discard
1173→
1174→  // Pause client_paused_1
1175→  json pause_req;
1176→  pause_req["command"] = "pause";
1177→  mock_->push_request("client_paused_1", pause_req.dump());
1178→  server_->process_requests();
1179→
1180→  json pause_response = mock_->pop_reply("client_paused_1");
1181→  ASSERT_FALSE(pause_response.is_discarded());
1182→  EXPECT_TRUE(pause_response["paused"].get<bool>());
1183→
1184→  // Clear any binary sends from previous operations
1185→  mock_->clear_binary_sends();
1186→
1187→  // Spin the node to let the publish timer fire
1188→  auto start = std::chrono::steady_clock::now();
1189→  while (std::chrono::steady_clock::now() - start < std::chrono::milliseconds(60)) {
1190→    rclcpp::spin_some(node_);
1191→    std::this_thread::sleep_for(std::chrono::milliseconds(5));
1192→  }
1193→
1194→  // Verify binary sends - since topics don't exist, no messages are buffered
1195→  // so no binary sends should occur. But if messages were buffered,
1196→  // only client_active_1 would receive them, not client_paused_1.
1197→  auto binary_sends = mock_->get_binary_sends();
1198→  for (const auto& [client_id, data] : binary_sends) {
1199→    // If any binary sends occurred, they should NOT be to the paused client
1200→    EXPECT_NE(client_id, "client_paused_1") << "Paused client should not receive binary frames";
1201→  }
1202→}
