1247→// ===========================================================================
1248→// REGRESSION TESTS - Critical bugs found in code review
1249→// ===========================================================================
1250→
1251→// ---------------------------------------------------------------------------
1252→// RegressionTest_BinaryFrameIncludesHeader
1253→//
1254→// Regression test for bug: finalize() not called in publish_aggregated_messages().
1255→// Binary frames MUST include the 16-byte header with magic "PJRB" (0x42524A50).
1256→// Without this fix, compress_zstd() was called directly, skipping the header.
1257→// ---------------------------------------------------------------------------
1258→TEST_F(BridgeServerTest, RegressionTest_BinaryFrameIncludesHeader) {
1259→  // This test verifies that when binary data is sent, it includes the
1260→  // 16-byte header with magic bytes "PJRB" at the start.
1261→  //
1262→  // The bug was: publish_aggregated_messages() called compress_zstd() directly
1263→  // instead of finalize(), so the header was never prepended.
1264→
1265→  // We can't easily trigger actual message publishing in unit tests without
1266→  // real ROS topics, but we can verify the serializer's finalize() method
1267→  // is correctly producing the header format by checking the protocol constants.
1268→
1269→  // Verify the expected magic value matches "PJRB" in little-endian
1270→  constexpr uint32_t expected_magic = 0x42524A50;  // "PJRB"
1271→  const char* magic_bytes = reinterpret_cast<const char*>(&expected_magic);
1272→  EXPECT_EQ(magic_bytes[0], 'P');
1273→  EXPECT_EQ(magic_bytes[1], 'J');
1274→  EXPECT_EQ(magic_bytes[2], 'R');
1275→  EXPECT_EQ(magic_bytes[3], 'B');
1276→
1277→  // Note: The actual integration test that binary frames sent to clients
1278→  // include this header is covered by the message_serializer tests
1279→  // (FinalizeIncludesBinaryHeader, HeaderMagicIsPJRB) which verify finalize()
1280→  // produces correct output. This test documents the regression.
1281→}
1282→
1283→// ---------------------------------------------------------------------------
1284→// RegressionTest_PausedClientDisconnectNoDoubleDecrement
1285→//
1286→// Regression test for bug: double-decrement of subscription ref counts when
1287→// a paused client disconnects.
1288→//
1289→// The bug was: handle_pause() decremented ref counts, then cleanup_session()
1290→// also decremented them again on disconnect, causing ref count corruption.
1291→//
1292→// Fix: cleanup_session() now checks if client was paused before unsubscribing.
1293→// ---------------------------------------------------------------------------
1294→TEST_F(BridgeServerTest, RegressionTest_PausedClientDisconnectNoDoubleDecrement) {
1295→  ASSERT_TRUE(server_->initialize());
1296→
1297→  // Client 1: Create session, pause, then disconnect
1298→  // This tests the core fix: cleanup_session should not unsubscribe if paused
1299→  const std::string client1 = "client_paused_disconnect";
1300→
1301→  // Create session
1302→  json hb;
1303→  hb["command"] = "heartbeat";
1304→  mock_->push_request(client1, hb.dump());
1305→  server_->process_requests();
1306→  mock_->pop_reply(client1);  // discard
1307→  EXPECT_EQ(server_->get_active_session_count(), 1u);
1308→
1309→  // Pause client1
1310→  json pause_req;
1311→  pause_req["command"] = "pause";
1312→  mock_->push_request(client1, pause_req.dump());
1313→  server_->process_requests();
1314→  json pause_resp = mock_->pop_reply(client1);
1315→  EXPECT_TRUE(pause_resp["paused"].get<bool>());
1316→
1317→  // Simulate disconnect while paused
1318→  // Before the fix, cleanup_session would try to unsubscribe even though
1319→  // pause already decremented ref counts, causing double-decrement
1320→  mock_->simulate_disconnect(client1);
1321→
1322→  // Verify session was cleaned up without crash or error
1323→  EXPECT_EQ(server_->get_active_session_count(), 0u);
1324→
1325→  // Client 2: Create a new session after the paused disconnect
1326→  // This verifies the system is still in a good state
1327→  const std::string client2 = "client_after_paused_disconnect";
1328→
1329→  mock_->push_request(client2, hb.dump());
1330→  server_->process_requests();
1331→  json hb_resp = mock_->pop_reply(client2);
1332→
1333→  // Heartbeat should succeed - system is healthy
1334→  EXPECT_EQ(hb_resp["status"], "ok");
1335→  EXPECT_EQ(server_->get_active_session_count(), 1u);
1336→
1337→  // Clean disconnect of client2
1338→  mock_->simulate_disconnect(client2);
1339→  EXPECT_EQ(server_->get_active_session_count(), 0u);
1340→}
