109→bool BridgeServer::process_requests() {
110→  if (!initialized_) {
111→    RCLCPP_ERROR(node_->get_logger(), "Bridge server not initialized");
112→    return false;
113→  }
114→
115→  // Receive request (non-blocking)
116→  std::vector<uint8_t> request_data;
117→  std::string client_id;
118→  bool received = middleware_->receive_request(request_data, client_id);
119→
120→  if (!received || request_data.empty()) {
121→    return false;  // No request pending
122→  }
123→
124→  // Convert request data to string
125→  std::string request(request_data.begin(), request_data.end());
126→  if (client_id.empty()) {
127→    RCLCPP_WARN(node_->get_logger(), "Received request with no client identity");
128→    return true;
129→  }
130→
131→  // Parse request JSON
132→  std::string response;
133→  json request_json;
134→  try {
135→    request_json = json::parse(request);
136→
137→    if (!request_json.contains("command")) {
138→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
139→    } else {
140→      std::string command = request_json["command"];
141→
142→      RCLCPP_DEBUG(node_->get_logger(), "Processing '%s' command from client '%s'", command.c_str(), client_id.c_str());
143→
144→      // Route to appropriate handler
145→      if (command == "get_topics") {
146→        response = handle_get_topics(client_id, request_json);
147→      } else if (command == "subscribe") {
148→        response = handle_subscribe(client_id, request_json);
149→      } else if (command == "unsubscribe") {
150→        response = handle_unsubscribe(client_id, request_json);
151→      } else if (command == "heartbeat") {
152→        response = handle_heartbeat(client_id, request_json);
153→      } else if (command == "pause") {
154→        response = handle_pause(client_id, request_json);
155→      } else if (command == "resume") {
156→        response = handle_resume(client_id, request_json);
157→      } else {
158→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
159→      }
160→    }
161→  } catch (const json::exception& e) {
162→    RCLCPP_ERROR(node_->get_logger(), "JSON parse error: %s", e.what());
163→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
164→  } catch (const std::exception& e) {
165→    RCLCPP_ERROR(node_->get_logger(), "Error processing request: %s", e.what());
166→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
167→  }
168→
169→  // Send response to the specific client
170→  std::vector<uint8_t> response_data(response.begin(), response.end());
171→  middleware_->send_reply(client_id, response_data);
172→  return true;
173→}
