207→std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
208→  // Create session if it doesn't exist
209→  if (!session_manager_->session_exists(client_id)) {
210→    session_manager_->create_session(client_id);
211→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
212→  }
213→
214→  // Update heartbeat
215→  session_manager_->update_heartbeat(client_id);
216→
217→  if (!request.contains("topics")) {
218→    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
219→  }
220→
221→  if (!request["topics"].is_array()) {
222→    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
223→  }
224→
225→  // Get current subscriptions
226→  auto current_subs = session_manager_->get_subscriptions(client_id);
227→
228→  // Parse requested topics — supports mixed array of strings and objects:
229→  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
230→  std::unordered_map<std::string, double> requested_topics;
231→  for (const auto& topic : request["topics"]) {
232→    if (topic.is_string()) {
233→      requested_topics[topic.get<std::string>()] = 0.0;
234→    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
235→      double rate_hz = 0.0;
236→      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
237→        rate_hz = topic["max_rate_hz"].get<double>();
238→        if (rate_hz < 0.0) {
239→          rate_hz = 0.0;
240→        }
241→      }
242→      requested_topics[topic["name"].get<std::string>()] = rate_hz;
243→    }
244→  }
245→
246→  // Determine which topics to add (additive model - subscribe only adds, never removes)
247→  std::vector<std::string> topics_to_add;
248→
249→  // Find topics to add (in requested but not in current)
250→  for (const auto& [topic, rate] : requested_topics) {
251→    if (current_subs.find(topic) == current_subs.end()) {
252→      topics_to_add.push_back(topic);
253→    }
254→  }
255→
256→  // Get all available topics
257→  auto available_topics = topic_discovery_->discover_topics();
258→  std::unordered_map<std::string, std::string> topic_types;
259→  for (const auto& topic : available_topics) {
260→    topic_types[topic.name] = topic.type;
261→  }
262→
263→  // Subscribe to new topics - track successes and failures
264→  json schemas = json::object();
265→  json failures = json::array();
266→  std::unordered_set<std::string> successfully_subscribed;
267→
268→  for (const auto& topic_name : topics_to_add) {
269→    // Check if topic exists
270→    if (topic_types.find(topic_name) == topic_types.end()) {
271→      RCLCPP_WARN(
272→          node_->get_logger(), "Client '%s' requested non-existent topic '%s'", client_id.c_str(), topic_name.c_str());
273→      json failure;
274→      failure["topic"] = topic_name;
275→      failure["reason"] = "Topic does not exist";
276→      failures.push_back(failure);
277→      continue;
278→    }
279→
280→    std::string topic_type = topic_types[topic_name];
281→
282→    // Create callback to add messages to buffer (with optional stripping)
283→    auto callback = [this, topic_type](
284→                        const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg,
285→                        uint64_t receive_time_ns) {
286→      if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
287→        auto stripped = MessageStripper::strip(topic_type, *msg);
288→        auto stripped_ptr = std::make_shared<rclcpp::SerializedMessage>(std::move(stripped));
289→        message_buffer_->add_message(topic, receive_time_ns, stripped_ptr);
290→      } else {
291→        message_buffer_->add_message(topic, receive_time_ns, msg);
292→      }
293→    };
294→
295→    // Get schema BEFORE subscribing to avoid corrupting the reference count
296→    // if schema extraction fails after subscribe() increments it.
297→    std::string schema;
298→    try {
299→      schema = schema_extractor_->get_message_definition(topic_type);
300→    } catch (const std::exception& e) {
301→      RCLCPP_ERROR(node_->get_logger(), "Failed to get schema for topic '%s': %s", topic_name.c_str(), e.what());
302→      json failure;
303→      failure["topic"] = topic_name;
304→      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
305→      failures.push_back(failure);
306→      continue;
307→    }
308→
309→    // Subscribe via subscription manager
310→    bool success = subscription_manager_->subscribe(topic_name, topic_type, callback);
311→    if (!success) {
312→      RCLCPP_ERROR(node_->get_logger(), "Failed to subscribe to topic '%s'", topic_name.c_str());
313→      json failure;
314→      failure["topic"] = topic_name;
315→      failure["reason"] = "Subscription manager failed to create subscription";
316→      failures.push_back(failure);
317→      continue;
318→    }
319→
320→    nlohmann::json schema_obj;
321→    schema_obj["encoding"] = kSchemaEncodingRos2Msg;
322→    schema_obj["definition"] = schema;
323→    schemas[topic_name] = schema_obj;
324→    successfully_subscribed.insert(topic_name);
325→
326→    RCLCPP_INFO(
327→        node_->get_logger(), "Client '%s' subscribed to topic '%s' (type: %s)", client_id.c_str(), topic_name.c_str(),
328→        topic_type.c_str());
329→  }
330→
331→  // Update session subscriptions with successfully subscribed topics (additive model)
332→  std::unordered_map<std::string, double> final_subscriptions = current_subs;
333→  for (const auto& topic : successfully_subscribed) {
334→    final_subscriptions[topic] = requested_topics[topic];
335→  }
336→  // Update rates for topics that were already subscribed but may have a new rate
337→  for (const auto& [topic, rate] : requested_topics) {
338→    if (final_subscriptions.find(topic) != final_subscriptions.end()) {
339→      final_subscriptions[topic] = rate;
340→    }
341→  }
342→  session_manager_->update_subscriptions(client_id, final_subscriptions);
343→
344→  // Build response
345→  json response;
346→  if (failures.empty()) {
347→    response["status"] = "success";
348→  } else if (schemas.empty()) {
349→    // All subscriptions failed
350→    response["status"] = "error";
351→    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
352→    response["message"] = "Failed to subscribe to all requested topics";
353→  } else {
354→    // Partial success
355→    response["status"] = "partial_success";
356→    response["message"] = "Some subscriptions failed";
357→  }
358→
359→  response["schemas"] = schemas;
360→  if (!failures.empty()) {
361→    response["failures"] = failures;
362→  }
363→
364→  // Include rate limits in response for topics with non-zero rates
365→  json rate_limits = json::object();
366→  for (const auto& [topic, rate] : final_subscriptions) {
367→    if (rate > 0.0) {
368→      rate_limits[topic] = rate;
369→    }
370→  }
371→  if (!rate_limits.empty()) {
372→    response["rate_limits"] = rate_limits;
373→  }
374→
375→  inject_response_fields(response, request);
376→
377→  return response.dump();
378→}
