380→std::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
381→  // Create session if it doesn't exist
382→  if (!session_manager_->session_exists(client_id)) {
383→    session_manager_->create_session(client_id);
384→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
385→  }
386→
387→  // Update heartbeat
388→  session_manager_->update_heartbeat(client_id);
389→
390→  // Validate topics field
391→  if (!request.contains("topics") || !request["topics"].is_array()) {
392→    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
393→  }
394→
395→  // Get current subscriptions
396→  auto current_subs = session_manager_->get_subscriptions(client_id);
397→
398→  std::vector<std::string> removed;
399→
400→  for (const auto& topic_item : request["topics"]) {
401→    std::string topic_name;
402→    if (topic_item.is_string()) {
403→      topic_name = topic_item.get<std::string>();
404→    } else {
405→      continue;  // Skip invalid entries
406→    }
407→
408→    // Check if subscribed
409→    if (current_subs.find(topic_name) != current_subs.end()) {
410→      // Decrement subscription ref count
411→      subscription_manager_->unsubscribe(topic_name);
412→
413→      // Remove from client subscriptions
414→      current_subs.erase(topic_name);
415→
416→      removed.push_back(topic_name);
417→
418→      RCLCPP_INFO(
419→          node_->get_logger(), "Client '%s' unsubscribed from topic '%s'", client_id.c_str(), topic_name.c_str());
420→    }
421→  }
422→
423→  // Update session subscriptions
424→  session_manager_->update_subscriptions(client_id, current_subs);
425→
426→  // Build response
427→  json response;
428→  response["status"] = "success";
429→  response["removed"] = removed;
430→  inject_response_fields(response, request);
431→
432→  return response.dump();
433→}
