496→std::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
497→  // Create session if it doesn't exist
498→  if (!session_manager_->session_exists(client_id)) {
499→    session_manager_->create_session(client_id);
500→    RCLCPP_INFO(node_->get_logger(), "Created new session for client '%s'", client_id.c_str());
501→  }
502→
503→  // Update heartbeat
504→  session_manager_->update_heartbeat(client_id);
505→
506→  // Check if not paused (idempotent)
507→  if (!session_manager_->is_paused(client_id)) {
508→    RCLCPP_DEBUG(node_->get_logger(), "Client '%s' not paused", client_id.c_str());
509→    json response;
510→    response["status"] = "ok";
511→    response["paused"] = false;
512→    inject_response_fields(response, request);
513→    return response.dump();
514→  }
515→
516→  // Set unpaused state
517→  session_manager_->set_paused(client_id, false);
518→
519→  // Smart ROS2 management: increment ref counts for all subscribed topics
520→  // Get all available topics for type lookup
521→  auto available_topics = topic_discovery_->discover_topics();
522→  std::unordered_map<std::string, std::string> topic_types;
523→  for (const auto& topic : available_topics) {
524→    topic_types[topic.name] = topic.type;
525→  }
526→
527→  auto subs = session_manager_->get_subscriptions(client_id);
528→  for (const auto& [topic, rate] : subs) {
529→    auto type_it = topic_types.find(topic);
530→    if (type_it != topic_types.end()) {
531→      std::string topic_type = type_it->second;
532→      auto callback = [this, topic_type](
533→                          const std::string& t, const std::shared_ptr<rclcpp::SerializedMessage>& msg,
534→                          uint64_t receive_time_ns) {
535→        if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
536→          auto stripped = MessageStripper::strip(topic_type, *msg);
537→          auto stripped_ptr = std::make_shared<rclcpp::SerializedMessage>(std::move(stripped));
538→          message_buffer_->add_message(t, receive_time_ns, stripped_ptr);
539→        } else {
540→          message_buffer_->add_message(t, receive_time_ns, msg);
541→        }
542→      };
543→      subscription_manager_->subscribe(topic, topic_type, callback);
544→      RCLCPP_DEBUG(
545→          node_->get_logger(), "Incremented ref count for topic '%s' (client '%s' resumed)", topic.c_str(),
546→          client_id.c_str());
547→    } else {
548→      RCLCPP_WARN(
549→          node_->get_logger(), "Topic '%s' no longer exists, cannot re-subscribe for client '%s'", topic.c_str(),
550→          client_id.c_str());
551→    }
552→  }
553→
554→  RCLCPP_INFO(node_->get_logger(), "Client '%s' resumed (%zu topics refs incremented)", client_id.c_str(), subs.size());
555→
556→  json response;
557→  response["status"] = "ok";
558→  response["paused"] = false;
559→  inject_response_fields(response, request);
560→  return response.dump();
561→}
562→
563→void BridgeServer::inject_response_fields(nlohmann::json& response, const nlohmann::json& request) const {
564→  response["protocol_version"] = kProtocolVersion;
565→  if (request.contains("id") && request["id"].is_string()) {
566→    response["id"] = request["id"];
567→  }
568→}
569→
570→std::string BridgeServer::create_error_response(
571→    const std::string& error_code, const std::string& message, const nlohmann::json& request) const {
572→  json response;
573→  response["status"] = "error";
574→  response["error_code"] = error_code;
575→  response["message"] = message;
576→  inject_response_fields(response, request);
577→
578→  return response.dump();
579→}
580→
581→void BridgeServer::check_session_timeouts() {
582→  auto timed_out_sessions = session_manager_->get_timed_out_sessions();
583→
584→  for (const auto& client_id : timed_out_sessions) {
585→    RCLCPP_WARN(node_->get_logger(), "Session timeout for client '%s'", client_id.c_str());
586→
587→    cleanup_session(client_id);
588→  }
589→}
590→
591→void BridgeServer::cleanup_session(const std::string& client_id) {
592→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
593→
594→  // Check if session still exists (idempotency guard)
595→  if (!session_manager_->session_exists(client_id)) {
596→    return;
597→  }
598→
599→  // Get client's subscriptions and paused state
600→  auto subscriptions = session_manager_->get_subscriptions(client_id);
601→  bool was_paused = session_manager_->is_paused(client_id);
602→
603→  // Unsubscribe from all topics (only if not paused - paused clients already decremented ref counts)
604→  if (!was_paused) {
605→    for (const auto& [topic, rate] : subscriptions) {
606→      subscription_manager_->unsubscribe(topic);
607→      RCLCPP_DEBUG(node_->get_logger(), "Unsubscribed client '%s' from topic '%s'", client_id.c_str(), topic.c_str());
608→    }
609→  }
610→
611→  // Remove session
612→  session_manager_->remove_session(client_id);
613→
614→  // Clean up rate-limit tracking for this client
615→  {
616→    std::lock_guard<std::mutex> lock(last_sent_mutex_);
617→    last_sent_times_.erase(client_id);
618→  }
619→
620→  RCLCPP_INFO(
621→      node_->get_logger(), "Cleaned up session for client '%s' (%zu topics unsubscribed)", client_id.c_str(),
622→      subscriptions.size());
623→}
624→
625→size_t BridgeServer::get_active_session_count() const {
626→  return session_manager_->session_count();
627→}
628→
629→std::pair<uint64_t, uint64_t> BridgeServer::get_publish_stats() const {
630→  std::lock_guard<std::mutex> lock(stats_mutex_);
631→  return {total_messages_published_, total_bytes_published_};
632→}
633→
634→void BridgeServer::publish_aggregated_messages() {
635→  // Get all new messages from buffer
636→  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
637→  message_buffer_->move_messages(messages);
638→
639→  if (messages.empty()) {
640→    // No new messages, skip publishing
641→    return;
642→  }
643→
644→  try {
645→    // Get active sessions for per-client filtering
646→    auto active_sessions = session_manager_->get_active_sessions();
647→    if (active_sessions.empty()) {
648→      return;
649→    }
650→
651→    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
652→    // Key: map of topic -> rate_mhz (milli-Hz as int, avoids float equality issues).
653→    // Clients with identical topic+rate configs share the same compressed buffer.
654→    using GroupKey = std::map<std::string, int>;
655→    std::map<GroupKey, std::vector<std::string>> subscription_groups;
656→    // Also store the per-client subscription map for rate filtering
657→    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
658→
659→    for (const auto& client_id : active_sessions) {
660→      auto subs = session_manager_->get_subscriptions(client_id);
661→      if (subs.empty()) {
662→        continue;
663→      }
664→      GroupKey key;
665→      for (const auto& [topic, rate_hz] : subs) {
666→        key[topic] = static_cast<int>(rate_hz * 1000);
667→      }
668→      subscription_groups[key].push_back(client_id);
669→      client_subs[client_id] = std::move(subs);
670→    }
671→
672→    size_t total_msg_count = 0;
673→    size_t total_bytes = 0;
674→
675→    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
676→
677→    for (const auto& [group_key, client_ids] : subscription_groups) {
678→      // Serialize once for this subscription group
679→      AggregatedMessageSerializer serializer;
680→      size_t group_msg_count = 0;
681→
682→      // Use the first client's subs to get rate info (all clients in group have same config)
683→      const auto& representative_subs = client_subs[client_ids.front()];
684→      // Get this representative client's last-sent times for rate filtering
685→      auto& rep_last_sent = last_sent_times_[client_ids.front()];
686→
687→      for (const auto& [topic, msgs] : messages) {
688→        auto sub_it = representative_subs.find(topic);
689→        if (sub_it == representative_subs.end()) {
690→          continue;
691→        }
692→
693→        double rate_hz = sub_it->second;
694→        int rate_mhz = static_cast<int>(rate_hz * 1000);
695→
696→        if (rate_mhz == 0) {
697→          // Unlimited: serialize all messages
698→          for (const auto& msg : msgs) {
699→            serializer.serialize_message(topic, msg.timestamp_ns, *(msg.msg));
700→            group_msg_count++;
701→          }
702→        } else {
703→          // Rate limited: compute minimum interval in nanoseconds
704→          // rate_mhz is in milli-Hz, so interval = 1e12 / rate_mhz nanoseconds
705→          uint64_t min_interval_ns = 1'000'000'000'000ULL / static_cast<uint64_t>(rate_mhz);
706→          uint64_t last_sent = rep_last_sent[topic];  // 0 if not yet sent
707→
708→          for (const auto& msg : msgs) {
709→            if (msg.timestamp_ns >= last_sent + min_interval_ns) {
710→              serializer.serialize_message(topic, msg.timestamp_ns, *(msg.msg));
711→              last_sent = msg.timestamp_ns;
712→              group_msg_count++;
713→            }
714→          }
715→          rep_last_sent[topic] = last_sent;
716→        }
717→      }
718→
719→      if (group_msg_count == 0) {
720→        continue;
721→      }
722→
723→      // Finalize with 16-byte header and compress
724→      std::vector<uint8_t> compressed_data = serializer.finalize();
725→
726→      // Send the same buffer to all clients in this group
727→      bool any_sent = false;
728→      for (const auto& client_id : client_ids) {
729→        // Skip paused clients - they should not receive binary frames
730→        if (session_manager_->is_paused(client_id)) {
731→          continue;
732→        }
733→        if (middleware_->send_binary(client_id, compressed_data)) {
734→          any_sent = true;
735→        }
736→        // Sync last-sent times from representative to all clients in group
737→        if (client_id != client_ids.front()) {
738→          last_sent_times_[client_id] = rep_last_sent;
739→        }
740→      }
741→
742→      // Count messages once per group (not per client) to avoid inflation
743→      if (any_sent) {
744→        total_msg_count += group_msg_count;
745→        total_bytes += compressed_data.size();
746→      }
747→    }
748→
749→    if (total_msg_count > 0) {
750→      std::lock_guard<std::mutex> lock(stats_mutex_);
751→      total_messages_published_ += total_msg_count;
752→      total_bytes_published_ += total_bytes;
753→    }
754→  } catch (const std::exception& e) {
755→    RCLCPP_ERROR(node_->get_logger(), "Error publishing aggregated messages: %s", e.what());
756→  }
757→}
758→
759→}  // namespace pj_ros_bridge
