 32→std::string SchemaExtractor::get_message_definition(const std::string& message_type) {
 33→  // Level 1 cache: Check if complete definition is cached
 34→  {
 35→    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 36→    auto it = definition_cache_.find(message_type);
 37→    if (it != definition_cache_.end()) {
 38→      return it->second;
 39→    }
 40→  }
 41→
 42→  // Cache miss - build the definition
 43→  std::string package_name;
 44→  std::string type_name;
 45→
 46→  if (!parse_message_type(message_type, package_name, type_name)) {
 47→    return "";
 48→  }
 49→
 50→  // Build the message definition by reading .msg files from ROS2 share directory
 51→  // and recursively expanding nested types
 52→  std::ostringstream result;
 53→  std::set<std::string> processed_types;
 54→
 55→  if (!build_message_definition_recursive(package_name, type_name, result, processed_types, true)) {
 56→    return "";
 57→  }
 58→
 59→  std::string definition = result.str();
 60→
 61→  // Store in cache
 62→  {
 63→    std::unique_lock<std::shared_mutex> lock(cache_mutex_);
 64→    definition_cache_[message_type] = definition;
 65→  }
 66→
 67→  return definition;
