 70→bool SchemaExtractor::build_message_definition_recursive(
 71→    const std::string& package_name, const std::string& type_name, std::ostringstream& output,
 72→    std::set<std::string>& processed_types, bool is_root) const {
 73→  const std::string full_type = package_name + "/" + type_name;
 74→
 75→  // Level 2 cache: Check if .msg file content is cached
 76→  std::string msg_content;
 77→  {
 78→    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 79→    auto it = msg_file_cache_.find(full_type);
 80→    if (it != msg_file_cache_.end()) {
 81→      msg_content = it->second;
 82→    }
 83→  }
 84→
 85→  // Cache miss - read the .msg file
 86→  if (msg_content.empty()) {
 87→    // Get package share directory
 88→    std::string package_share_dir;
 89→    try {
 90→      package_share_dir = ament_index_cpp::get_package_share_directory(package_name);
 91→    } catch (const std::exception& e) {
 92→      return false;
 93→    }
 94→
 95→    // Construct path to .msg file
 96→    std::string msg_file_path = package_share_dir + "/msg/" + type_name + ".msg";
 97→
 98→    std::ifstream msg_file(msg_file_path);
 99→    if (!msg_file.is_open()) {
100→      return false;
101→    }
102→
103→    // Read entire file into string
104→    std::ostringstream content_stream;
105→    std::string line;
106→    while (std::getline(msg_file, line)) {
107→      content_stream << line << "\n";
108→    }
109→    msg_content = content_stream.str();
110→
111→    // Store in cache
112→    {
113→      std::unique_lock<std::shared_mutex> lock(cache_mutex_);
114→      msg_file_cache_[full_type] = msg_content;
115→    }
116→  }
117→
118→  // Add separator for nested types (not for root type)
119→  if (!is_root) {
120→    output << "\n================================================================================\n";
121→    output << "MSG: " << full_type << "\n";
122→  }
123→
124→  // Process the .msg file content line by line
125→  std::istringstream msg_stream(msg_content);
126→  std::string line;
127→  std::vector<std::string> nested_types;
128→
129→  while (std::getline(msg_stream, line)) {
130→    output << line << "\n";
131→
132→    // Check if line contains a nested message type
133→    // Format: "package_name/MessageType field_name" or "MessageType field_name"
134→    std::istringstream line_stream(line);
135→    std::string first_word;
136→    line_stream >> first_word;
137→
138→    // Skip comments and empty lines
139→    if (first_word.empty() || first_word[0] == '#') {
140→      continue;
141→    }
142→
143→    // Check if this is a nested message type
144→    std::string nested_package;
145→    std::string nested_type;
146→
147→    if (first_word.find('/') != std::string::npos) {
148→      // Format: package_name/MessageType
149→      size_t slash_pos = first_word.find('/');
150→      nested_package = first_word.substr(0, slash_pos);
151→      nested_type = first_word.substr(slash_pos + 1);
152→
153→      // Remove array brackets if present
154→      size_t bracket_pos = nested_type.find('[');
155→      if (bracket_pos != std::string::npos) {
156→        nested_type = nested_type.substr(0, bracket_pos);
157→      }
158→    } else {
159→      // Check if it's a built-in type or a local type
160→      bool is_builtin =
161→          (first_word == "bool" || first_word == "byte" || first_word == "char" || first_word == "float32" ||
162→           first_word == "float64" || first_word == "int8" || first_word == "uint8" || first_word == "int16" ||
163→           first_word == "uint16" || first_word == "int32" || first_word == "uint32" || first_word == "int64" ||
164→           first_word == "uint64" || first_word == "string" || first_word == "wstring");
165→
166→      if (!is_builtin) {
167→        // It's a local type in the same package
168→        nested_package = package_name;
169→        nested_type = first_word;
170→
171→        // Remove array brackets if present
172→        size_t bracket_pos = nested_type.find('[');
173→        if (bracket_pos != std::string::npos) {
174→          nested_type = nested_type.substr(0, bracket_pos);
175→        }
176→      }
177→    }
178→
179→    // If we found a nested type, add it to the list
180→    if (!nested_type.empty()) {
181→      std::string full_nested_type = nested_package + "/" + nested_type;
182→      if (processed_types.find(full_nested_type) == processed_types.end()) {
183→        processed_types.insert(full_nested_type);
184→        nested_types.push_back(full_nested_type);
185→      }
186→    }
187→  }
188→  // std_msgs/Header always goes last
189→  if (nested_types.size() >= 2) {
190→    if (nested_types.at(0) == "std_msgs/Header") {
191→      nested_types.push_back(nested_types.at(0));
192→      nested_types.erase(nested_types.begin());
193→    }
194→  }
195→
196→  // Recursively process nested types in the order they appear
197→  for (const auto& nested_full_type : nested_types) {
198→    size_t slash_pos = nested_full_type.find('/');
199→    std::string nested_pkg = nested_full_type.substr(0, slash_pos);
200→    std::string nested_typ = nested_full_type.substr(slash_pos + 1);
201→
202→    build_message_definition_recursive(nested_pkg, nested_typ, output, processed_types, false);
203→  }
204→
205→  return true;
206→}
