227→std::string remove_comments_from_schema(const std::string& schema) {
228→  std::istringstream input(schema);
229→  std::ostringstream output;
230→  std::string line;
231→
232→  while (std::getline(input, line)) {
233→    // Find the position of '#' character
234→    size_t comment_pos = line.find('#');
235→
236→    if (comment_pos != std::string::npos) {
237→      // Keep everything before the '#', trim trailing whitespace
238→      std::string before_comment = line.substr(0, comment_pos);
239→
240→      // Trim trailing whitespace
241→      size_t end = before_comment.find_last_not_of(" \t\r\n");
242→      if (end != std::string::npos) {
243→        before_comment = before_comment.substr(0, end + 1);
244→      } else {
245→        before_comment = "";
246→      }
247→
248→      // Only add non-empty lines
249→      if (!before_comment.empty()) {
250→        output << before_comment << "\n";
251→      }
252→    } else {
253→      // No comment, keep the whole line
254→      output << line << "\n";
255→    }
256→  }
257→
258→  return output.str();
259→}
