class BridgeServerTest : public ::testing::Test {
 protected:
  void SetUp() override {
    rclcpp::init(0, nullptr);
    node_ = std::make_shared<rclcpp::Node>("test_bridge_server");
    mock_ = std::make_shared<MockMiddleware>();
